#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding employee-onboarding-checklist (15 tables)..."

cargo loco generate scaffold employee \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    email:string! \
    phone:string! \
    job_title:string! \
    department:string! \
    start_date:date \
    --htmx

cargo loco generate scaffold assessment \
    employee:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    emergency_contact_relationship:string! \
    address_line_1:string! \
    address_line_2:string! \
    city:string! \
    postcode:string! \
    --htmx

cargo loco generate scaffold assessment_pre_employment_checks \
    assessment:references \
    dbs_check_status:string! \
    dbs_certificate_number:string! \
    dbs_check_date:date \
    dbs_update_service_registered:string! \
    right_to_work_verified:string! \
    right_to_work_document_type:string! \
    right_to_work_expiry_date:date \
    references_received:int \
    references_required:int \
    references_satisfactory:string! \
    identity_verified:string! \
    pre_employment_notes:text! \
    --htmx

cargo loco generate scaffold assessment_occupational_health \
    assessment:references \
    oh_questionnaire_submitted:string! \
    oh_clearance_received:string! \
    oh_clearance_date:date \
    oh_restrictions:string! \
    oh_restriction_details:text! \
    hepatitis_b_status:string! \
    tb_screening_status:string! \
    immunisation_status:string! \
    fit_to_work:string! \
    occupational_health_notes:text! \
    --htmx

cargo loco generate scaffold assessment_mandatory_training \
    assessment:references \
    fire_safety_completed:string! \
    fire_safety_date:date \
    manual_handling_completed:string! \
    manual_handling_date:date \
    infection_control_completed:string! \
    infection_control_date:date \
    safeguarding_adults_completed:string! \
    safeguarding_adults_level:string! \
    safeguarding_children_completed:string! \
    safeguarding_children_level:string! \
    information_governance_completed:string! \
    information_governance_date:date \
    basic_life_support_completed:string! \
    basic_life_support_date:date \
    equality_diversity_completed:string! \
    health_safety_completed:string! \
    conflict_resolution_completed:string! \
    mandatory_training_notes:text! \
    --htmx

cargo loco generate scaffold assessment_professional_registration \
    assessment:references \
    registration_required:string! \
    regulatory_body:string! \
    regulatory_body_other:string! \
    registration_number:string! \
    registration_verified:string! \
    registration_expiry_date:date \
    registration_conditions:string! \
    registration_condition_details:text! \
    revalidation_date:date \
    indemnity_insurance:string! \
    professional_registration_notes:text! \
    --htmx

cargo loco generate scaffold assessment_it_systems_access \
    assessment:references \
    nhs_smartcard_issued:string! \
    nhs_smartcard_number:string! \
    email_account_created:string! \
    network_login_created:string! \
    clinical_system_access:string! \
    clinical_system_name:string! \
    clinical_system_training_completed:string! \
    rostering_system_access:string! \
    phone_extension:string! \
