cargo loco generate scaffold assessment_uniform_id_badge \
    assessment:references \
    uniform_required:string! \
    uniform_ordered:string! \
    uniform_received:string! \
    uniform_size:string! \
    id_badge_photo_taken:string! \
    id_badge_issued:string! \
    id_badge_number:string! \
    access_card_issued:string! \
    access_card_areas:text! \
    locker_allocated:string! \
    locker_number:string! \
    uniform_id_notes:text! \
    --htmx

cargo loco generate scaffold assessment_induction_programme \
    assessment:references \
    corporate_induction_completed:string! \
    corporate_induction_date:date \
    local_induction_completed:string! \
    local_induction_date:date \
    department_tour_completed:string! \
    introduced_to_team:string! \
    emergency_procedures_briefed:string! \
    policies_handbook_received:string! \
