    gdpr_training_completed:string! \
    duty_of_candour_briefed:string! \
    whistleblowing_policy_briefed:string! \
    employee_signed_off:string! \
    employee_sign_off_date:date \
    manager_signed_off:string! \
    manager_sign_off_date:date \
    manager_sign_off_name:string! \
    sign_off_compliance_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    completion_percentage:double! \
    completion_status:string! \
    overall_risk_level:string! \
    items_completed:int! \
    items_total:int! \
